sp_widget.client_script:
api.controller = function($scope, $window, $location, $timeout) {
	var c = this;
	/* ★FIX (edit pre-fill): do NOT overwrite c.data with {} — that throws away
       the server-loaded record (connection_name/url/username/password) in edit
       mode, leaving the form blank. Keep whatever the server provided. */
	c.data = c.data || {};
	c.loading = false;

	// Snackbar state
	c.showSnackbar = false;
	c.snackbarMessage = '';
	c.snackbarType = 'success';

	/* SHOW SNACKBAR */
	c.showToast = function(message, type) {
		c.snackbarMessage = message;
		c.snackbarType = type;
		c.showSnackbar = true;
		$timeout(function() {
			c.showSnackbar = false;
		}, 2500);
	};

	/* CONNECT (save: insert or update) */
	c.connect = function() {
		if (!c.data.connection_name || !c.data.url || !c.data.username || !c.data.password) {
			c.showToast('Please fill all required fields', 'error');
			return;
		}
		c.loading = true;
		c.data.action = "saveConnection";

		/* ★ EDIT: carry the sys_id so the server updates instead of inserting. */
		c.data.sys_id = c.data.sys_id || '';

		/* capture BEFORE the call — c.server.update() replaces c.data with the
           server's response, which may not carry sys_id back. */
		var wasEdit = !!c.data.sys_id;

		c.server.update().then(function(response) {
			c.loading = false;

			/* trust the server's own flag if present, else the pre-call capture */
			if (response && typeof response.isEdit !== 'undefined') {
				wasEdit = !!response.isEdit;
			}

			console.log('[SAVE] success=' + (response && response.success) +
									' wasEdit=' + wasEdit);

			if (response.success) {

				c.showToast(
					(wasEdit ? 'Connection updated successfully' : 'Connection saved successfully'),
					'success'
				);
				c.data.isEdit = wasEdit || !!(response.new_sys_id);
				if (response.new_sys_id) {
					c.data.sys_id = response.new_sys_id; // persist returned sys_id for safety
				}

				$timeout(function() {
					/* ★ Open-redirect fix: navigate via $location (portal router)
                       instead of $window.location.href. Targets are hardcoded page
                       ids, no user input. $location.search() changes the ?id= param
                       within the portal SPA. */
					var target = 'tracenow_connection_list';
					console.log('[SAVE] navigating to ' + target);
					$location.search('id', target);
				}, 1500);
			} else {
				c.showToast(response.error || 'Connection failed', 'error');
			}
		});
	};

	c.goBack = function() {
		/* ★ Open-redirect fix: portal navigation, hardcoded page id */
		$location.search('id', 'tracenow_connection_list');
	};
};

sp_widget.css:
.sp-layout {
  display: flex;
  max-height: calc(100vh - 64px);
  position: relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(155, 192, 252, 0.08) 50%,
    rgba(17, 106, 248, 0.12) 100%
  );
}
/* SIDEBAR */
.sidebar-area {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}
/* CONTENT */
.content-area {
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  height: 100%;
  gap: 30px;
  margin: 0px auto;
  overflow-y: auto;
  height: calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}
@media(max-width:1600px){
  .content-area{
    padding: 30px;
  }
}
/* BACK */
.back-link {
  color: #6b7280;
  text-decoration: none;
  font-size: 14px;
  transition: color 0.2s ease;
}
.back-link:hover {
  color: #116AF8;
}
a.back-link:focus,
a.back-link:active,
a.back-link:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}
/* HERO */
.hero-section {
  text-align: center;
}
.hero-section h1 {
  font-size: 26px;
  font-weight: 600;
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-section p {
  color: #6b7280;
}
/* INFO */
.info-banner {
  max-width: 520px;
  margin: 0px auto;
  padding: 12px 16px;
  border-radius: 10px;
  background: linear-gradient(135deg, #E8F1FE, #F0F6FE);
  color: #0A50F5;
  border: 2px solid #9BC0FC;
  box-shadow: 0 2px 8px rgba(17, 106, 248, 0.1);
}
/* CARD */
.form-card {
  width: 520px;
  margin: 0px auto;
  background: #fff;
  padding: 30px;
  border-radius: 14px;
  border: 1px solid #e5e7eb;
  box-shadow: 0 8px 20px rgba(17, 106, 248, 0.08);
  transition: all 0.3s ease;
}
.form-card:hover {
  box-shadow: 0 12px 30px rgba(17, 106, 248, 0.15);
  border-color: #9BC0FC;
}
/* HEADER */
.card-header {
  display: flex;
  gap: 10px;
  margin-bottom: 20px;
}
.card-header h3 {
  margin: 0;
  font-size: 18px;
  color: #0A50F5;
}
.card-header p {
  margin: 0;
  font-size: 13px;
  color: #6b7280;
}
/* FORM */
.form-group {
  margin-bottom: 18px;
}
.form-group label {
  font-size: 13px;
  font-weight: 600;
  color: #1e293b;
}
input, select {
  width: 100%;
  padding: 10px;
  border-radius: 8px;
  border: 1px solid #e5e7eb;
  background: #f9fafb;
  transition: all 0.2s ease;
}
input:focus, select:focus {
  border-color: #116AF8;
  background: #fff;
  outline: none;
  box-shadow: 0 0 0 3px rgba(17, 106, 248, 0.1);
}
/* BUTTONS */
.form-actions {
  display: flex;
  justify-content: space-between;
  margin-top: 20px;
  gap: 10px;
}
.btn-secondary {
  background: #f3f4f6;
  border: none;
  padding: 10px 18px;
  border-radius: 8px;
  color: #374151;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
}
.btn-secondary:hover {
  background: #e5e7eb;
}
.btn-light {
  background: linear-gradient(135deg, #E8F1FE, #D4E4FD);
  border: 1px solid #9BC0FC;
  padding: 10px 18px;
  border-radius: 8px;
  color: #0A50F5;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
}
.btn-light:hover {
  background: linear-gradient(135deg, #D4E4FD, #9BC0FC);
  transform: translateY(-1px);
}
.btn-primary {
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  box-shadow: 0 8px 20px rgba(17, 106, 248, 0.3);
  color: #fff;
  border: none;
  padding: 11px 18px;
  border-radius: 10px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
}
.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 25px rgba(10, 80, 245, 0.4);
  background: linear-gradient(135deg, #0A50F5, #116AF8);
}
button:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}
.dm-snackbar {
  position: fixed;
  bottom: 30px;
  right: 30px;
  min-width: 280px;
  max-width: 350px;
  padding: 16px 20px;
  border-radius: 12px;
  background: #1f2937;
  color: #fff;
  font-size: 14px;
  display: flex;
  align-items: center;
  gap: 10px;
  opacity: 0;
  transform: translateY(20px);
  transition: all 0.3s ease;
  z-index: 9999;
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.2);
}
.dm-snackbar.show {
  opacity: 1;
  transform: translateY(0);
}
.dm-snackbar.success {
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  box-shadow: 0 8px 20px rgba(17, 106, 248, 0.4);
}
.dm-snackbar.error {
  background: linear-gradient(to right, #ef4444, #f87171);
  box-shadow: 0 8px 20px rgba(239, 68, 68, 0.4);
}
.snackbar-content {
  display: flex;
  align-items: center;
  gap: 10px;
}
.snackbar-content i {
  font-size: 18px;
}

sp_widget.script:
(function() {

	data.side = $sp.getWidget('tracenow_sidebar');

	/* ============================================================
       ★ EDIT MODE (added): if opened with ?sys_id=…, load that
       connection so the form pre-fills with its existing values
       (incl. password). Runs only on the initial GET, not on save.
    ============================================================ */
	data.sys_id = $sp.getParameter('sys_id') || '';
	data.isEdit = false;

	if (data.sys_id && (!input || !input.action)) {
		var loadGR = new GlideRecordSecure('x_sysus_tracenow_connection');
		if (loadGR.get(data.sys_id) && loadGR.sys_created_by == gs.getUserName()) {
			data.isEdit          = true;
			data.connection_name = loadGR.getValue('name');
			data.url             = loadGR.getValue('url');
			data.username        = loadGR.getValue('username');
			data.password        = loadGR.getValue('password');
		} else {
			data.sys_id = '';   // not found / not owned → fall back to create mode
		}
	}


	if (input && input.action === "saveConnection") {

		/* ★ EDIT: are we updating an existing record we own? */
		var editing = false;
		var editGR  = new GlideRecordSecure('x_sysus_tracenow_connection');
		if (input.sys_id && editGR.get(input.sys_id) &&
				editGR.sys_created_by == gs.getUserName()) {
			editing = true;
		}

		var dup = new GlideRecordSecure('x_sysus_tracenow_connection');

		dup.addQuery('url', input.url);
		dup.addQuery('sys_created_by', gs.getUserName());
		/* ★ EDIT: don't let the record being edited collide with itself */
		if (editing) {
			dup.addQuery('sys_id', '!=', input.sys_id);
		}
		dup.query();

		if (dup.next()) {

			data.success = false;
			data.error = "A connection with this URL already exists.";

			return; // stop execution
		}
		/* ================= VALIDATE CONNECTION ================= */

		var connectionResult = validateAndFetchData(
			input.url,
			input.username,
			input.password
		);


		/* ================= SUCCESS CASE ================= */

		if (connectionResult.isValid) {

			var gr = new GlideRecordSecure('x_sysus_tracenow_connection');

			// ✅ get() loads the existing record into gr so update() works correctly
			if (editing) {
				gr.addQuery('sys_id', input.sys_id);
			} else {
				gr.initialize();
				gr.state = false;
			}

			gr.name     = input.connection_name;
			gr.url      = input.url;
			gr.username = input.username;
			gr.password = input.password;

			var sys_id = editing ? (gr.update() ? input.sys_id : '') : gr.insert();

			if (sys_id) {

				/* ================= SUCCESS NOTIFICATION ================= */

				var successNotif =
						new GlideRecordSecure(
							"x_sysus_tracenow_notifications"
						);

				successNotif.initialize();

				successNotif.user = gs.getUserID();

				successNotif.title =
					editing
					? "Connection Updated Successfully"
				: "Connection Created Successfully";

				successNotif.message =
					"Connection \"" +
					input.connection_name +
					"\" was verified and " +
					(editing ? "updated." : "saved.");

				successNotif.priority = "success";

				successNotif.read = false;

				successNotif.insert();


				/* ================= RESPONSE ================= */

				data.success = true;

				data.new_sys_id = sys_id;
				data.isEdit     = editing;

				data.message =
					"Connection successful and data verified.";

			}

			else {

				/* ================= SAVE FAILED NOTIFICATION ================= */

				var saveFailNotif =
						new GlideRecordSecure(
							"x_sysus_tracenow_notifications"
						);

				saveFailNotif.initialize();

				saveFailNotif.user = gs.getUserID();

				saveFailNotif.title =
					"Connection Save Failed";

				saveFailNotif.message =
					"Connection verified but failed to save locally.";

				saveFailNotif.priority = "error";

				saveFailNotif.read = false;

				saveFailNotif.insert();


				data.success = false;

				data.error =
					"Connection verified, but failed to save record.";

			}

		}


		/* ================= VALIDATION FAILURE CASE ================= */

		else {

			var failNotif =
					new GlideRecordSecure(
						"x_sysus_tracenow_notifications"
					);

			failNotif.initialize();

			failNotif.user = gs.getUserID();

			failNotif.title =
				"Connection Failed";

			failNotif.message =
				"Connection \"" +
				input.connection_name +
				"\" could not be verified. " +
				connectionResult.errorMessage;

			failNotif.priority = "error";

			failNotif.read = false;

			failNotif.insert();


			data.success = false;

			data.error =
				connectionResult.errorMessage;

		}

	}



	/* ================= VALIDATION FUNCTION ================= */

	function validateAndFetchData(
		instanceUrl,
		username,
		password
	) {

		var result = {
			isValid: false,
			errorMessage: ""
		};

		try {

			var r = new sn_ws.RESTMessageV2();

			r.setEndpoint(
				instanceUrl +
				'/api/now/table/sys_user?sysparm_limit=1'
			);

			r.setHttpMethod('GET');

			r.setBasicAuth(
				username,
				password
			);

			r.setRequestHeader(
				'Accept',
				'application/json'
			);

			var response = r.execute();

			var responseBody =
					response.getBody();

			var statusCode =
					response.getStatusCode();


			if (statusCode === 200) {

				var parsedData =
						JSON.parse(responseBody);

				if (
					parsedData.result &&
					parsedData.result.length > 0
				) {

					result.isValid = true;

				}

				else {

					result.errorMessage =
						"Connected but no records returned.";

				}

			}

			else if (statusCode === 401) {

				result.errorMessage =
					"Authentication failed: Invalid username or password.";

			}

			else {

				result.errorMessage =
					"Connection failed with status code: " +
					statusCode;

			}

		}

		catch (ex) {

			result.errorMessage =
				"Network error: " +
				ex.message;

		}

		return result;

	}

})();
